// 1. Ambil data sebagai Array (menggunakan .all())
const rawData = $input.all().map(item => item.json); 
const JAM_MASUK_STANDAR = "07:15";
const JAM_PULANG_STANDAR = "14:30";
const LIMIT_MENIT = 7 * 60 + 15; // 480 Menit

// 2. Fungsi Helper untuk konversi waktu ke menit
function toMinutes(timeStr) {
    if (!timeStr) return 0;
    const [h, m] = timeStr.split(':').map(Number);
    return (h * 60) + m;
}

// 3. Fungsi hitung selisih "DI LUAR JAM"
function hitungSelisih(jenisAbsen, jamAbsen) {
    const menitAbsen = toMinutes(jamAbsen);

    if (jenisAbsen.includes("MASUK")) {
        const menitStandar = toMinutes(JAM_MASUK_STANDAR);
        return menitAbsen > menitStandar ? menitAbsen - menitStandar : 0;
    } 

    if (jenisAbsen.includes("PULANG")) {
        const menitStandar = toMinutes(JAM_PULANG_STANDAR);
        return menitAbsen < menitStandar ? menitStandar - menitAbsen : 0;
    }

    return 0;
}

// 4. Proses Akumulasi
const akumulasiPegawai = {};

// Sekarang rawData sudah pasti berbentuk Array
rawData.forEach(item => {
    if (item.Tanggal && item["Jenis Absen"] && item["Jenis Absen"].includes("DI LUAR JAM")) {
        const id = item.ID;
        const nama = item.Nama;

        if (!akumulasiPegawai[id]) {
            akumulasiPegawai[id] = { id: id, nama: nama, totalMenit: 0 };
        }

        akumulasiPegawai[id].totalMenit += hitungSelisih(item["Jenis Absen"], item.Jam);
    }
});

// 5. Filter pegawai yang akumulasinya >= 8 Jam
const hasilFilter = Object.values(akumulasiPegawai)
    .filter(p => p.totalMenit >= LIMIT_MENIT)
    .map(p => ({
        id: p.id,
        nama: p.nama,
        akumulasiWaktu: `${Math.floor(p.totalMenit / 60)}j ${p.totalMenit % 60}m`,
        totalMenit: p.totalMenit
    }));

const daftarPesan = hasilFilter.map(p => {
    return {
        id: p.id,
        nama: p.nama,
        pesan: `🔔 *PERINGATAN AKUMULASI WAKTU*\n` +
               `───────────────────\n` +
               `Yth. Bapak/Ibu *${p.nama}*,\n\n` +
               `Melalui pesan otomatis ini, kami menginformasikan bahwa akumulasi waktu "Di Luar Jam" (Keterlambatan & Pulang Cepat) Anda telah mencapai batas maksimum.\n\n` +
               `📊 *Detail Akumulasi:*\n` +
               `• Total Waktu: *${p.akumulasiWaktu}*\n` +
               `• Ambang Batas: 8 Jam (480 Menit)\n\n` +
               `Sesuai dengan peraturan yang berlaku, akumulasi ini setara dengan 1 hari kerja. Mohon segera melakukan konfirmasi ke bagian Kepegawaian untuk klarifikasi atau tindak lanjut administratif.\n\n` +
               `_Terima kasih atas perhatiannya._\n` +
               `───────────────────\n` +
               `*Sistem Absensi Digital*`
    };
});

return daftarPesan;

