// 1. Ambil data dari input
const pegawai = $input.all().map(item => item.json);
const logAbsen = $('Get Log Masuk').all().map(item => item.json);
const tanggal = $('Read Tanggal Masuk').first().json.tanggal;
const jamTarget = $('Read Tanggal Masuk').first().json.jam; // Sesuaikan jam pengingat

// 2. Buat Set ID pegawai yang sudah absen masuk hari ini
//    (mencakup "MASUK" dan "DI LUAR JAM MASUK" — keduanya tetap dianggap sudah absen)
const sudahAbsenIds = new Set(
  logAbsen
    .filter(log =>
      log.Tanggal === tanggal &&
      (log['Jenis Absen'] === 'MASUK' || log['Jenis Absen'] === 'DI LUAR JAM MASUK')
    )
    .map(log => String(log.ID))
);

// 3. Filter pegawai AKTIF yang BELUM absen masuk
const belumAbsen = pegawai.filter(p =>
  String(p.Status).toUpperCase() === 'AKTIF' &&
  !sudahAbsenIds.has(String(p.id))
);

// 4. Format output — satu item per pegawai (untuk dikirim notifikasi individual)
return belumAbsen.map(p => {
  const pesan =
    `⚠️ *PENGINGAT ABSENSI MASUK*\n\n` +
    `Halo *${p.username || p.Nama}*,\n` +
    `Hingga pukul *${jamTarget}* WITA, Anda tercatat *BELUM melakukan absensi MASUK* hari ini.\n\n` +
    `Mohon segera melakukan absensi melalui aplikasi.`;

  return {
    json: {
      id: p.id,
      username: p.username || p.Nama,
      NIP: p.NIP,
      Jabatan: p.Jabatan,
      Status: p.Status,
      nomorhp: p.nomorhp,
      tanggal,
      sudahAbsen: false,
      pesan
    }
  };
});

