// 1. Ambil data dari input
const pegawai   = $input.all().map(item => item.json);
const logAbsen  = $('Cek Log Pulang').all().map(item => item.json); // ← PERBAIKI INI
const tanggal   = $('Read Tanggal Pulang').first().json.tanggal;
const jamTarget = $('Read Tanggal Pulang').first().json.jam;

// 2. Filter log hanya untuk tanggal hari ini
const logHariIni = logAbsen.filter(log => log.Tanggal === tanggal);

// 3. ID yang sudah absen MASUK hari ini
const sudahMasukIds = new Set(
  logHariIni
    .filter(log =>
      log['Jenis Absen'] === 'MASUK' ||
      log['Jenis Absen'] === 'DI LUAR JAM MASUK'
    )
    .map(log => String(log.ID))
);

// 4. ID yang sudah absen PULANG hari ini
const sudahPulangIds = new Set(
  logHariIni
    .filter(log =>
      log['Jenis Absen'] === 'PULANG'             ||
      log['Jenis Absen'] === 'DI LUAR JAM PULANG' ||
      log['Jenis Absen'] === 'PULANG LUAR'
    )
    .map(log => String(log.ID))
);

// 5. Filter pegawai AKTIF yang sudah MASUK tapi belum PULANG
const belumPulang = pegawai.filter(p =>
  String(p.Status).toUpperCase() === 'AKTIF' &&
  sudahMasukIds.has(String(p.id)) &&
  !sudahPulangIds.has(String(p.id))
);

// 6. Format output — satu item per pegawai
return belumPulang.map(p => {
  const pesan =
    `⚠️ *PENGINGAT ABSENSI PULANG*\n\n` +
    `Halo *${p.username || p.Nama}*,\n` +
    `Anda tercatat sudah hadir, namun *belum melakukan absensi PULANG*.\n` +
    `Batas jam pulang: 14:30 WITA.`;
  return {
    json: {
      id         : p.id,
      username   : p.username || p.Nama,
      NIP        : p.NIP,
      Jabatan    : p.Jabatan,
      Status     : p.Status,
      nomorhp    : p.nomorhp,
      tanggal,
      sudahMasuk : true,
      sudahPulang: false,
      pesan
    }
  };
});

