// ╔════════════════════════════════════════════════════════╗
// ║   AUTO ABSEN TANPA BERITA v1 — BAPPERIDA Sumba Barat   ║
// ║   Cron: 10:00 WITA setiap hari kerja                   ║
// ║   • Skip jika hari libur nasional                      ║
// ║   • Skip pegawai yang sudah absen / ada keterangan     ║
// ║   • Skip pegawai NONAKTIF / CUTI / SAKIT / TUGAS       ║
// ╚════════════════════════════════════════════════════════╝

const tanggal = $('Read Tanggal TB').first().json.tanggal;
const jam     = $('Read Tanggal TB').first().json.jam.slice(0, 5);

// ── 1. Cek hari libur nasional ──
const liburRows = $('Get Libur Hari Ini TB').all().map(i => i.json);
const isLibur   = liburRows.some(r =>
  String(r.tanggal || r.Tanggal || '').trim() === tanggal
);
if (isLibur) {
  console.log(`[TB] Skip: ${tanggal} adalah hari libur nasional.`);
  return [];
}

// ── 2. Ambil log hari ini (Untuk cek siapa yang sudah absen/izin) ──
const logHariIni = $('Get Log Hari Ini TB').all().map(i => i.json)
  .filter(r => String(r.Tanggal || '').trim() === tanggal);

const sudahMasukIds = new Set(
  logHariIni
    .filter(r => ['MASUK', 'DI LUAR JAM MASUK'].includes(
      String(r['Jenis Absen'] || '').toUpperCase().trim()
    ))
    .map(r => String(r.ID || '').trim())
);

const sudahKetIds = new Set(
  logHariIni
    .filter(r => ['IZIN', 'SAKIT', 'TUGAS', 'TUBEL', 'CUTI', 'TANPA BERITA'].includes(
      String(r['Jenis Absen'] || '').toUpperCase().trim()
    ))
    .map(r => String(r.ID || '').trim())
);

// ── 3. Filter pegawai yang layak ditembak TANPA BERITA ──
const pegawai = $input.all().map(i => i.json);

const belumAbsen = pegawai.filter(p => {
  const id     = String(p.id || '').trim();
  const nama   = p.Nama || p.nama || p.username || '—';
  const status = String(p.Status || p.status || 'AKTIF').toUpperCase().trim();

  // LOGIKA FILTER:
  // Kita hanya memproses yang statusnya 'AKTIF'. 
  // Jika statusnya 'TUGAS', 'CUTI', 'SAKIT', atau 'NONAKTIF', maka otomatis SKIP.
  const isAktif = status === 'AKTIF';

  // Cek apakah ID ada, statusnya AKTIF, dan belum ada di log (Masuk/Keterangan)
  const layakDitembak = id && isAktif && !sudahMasukIds.has(id) && !sudahKetIds.has(id);

  if (id && !isAktif) {
    console.log(`[TB] Skip ${nama}: Status saat ini adalah ${status}`);
  }

  return layakDitembak;
});

if (!belumAbsen.length) {
  console.log(`[TB] ${tanggal}: semua pegawai sudah absen atau berstatus khusus (Tugas/Cuti/Sakit).`);
  return [];
}

console.log(`[TB] ${tanggal}: ${belumAbsen.length} pegawai dicatat TANPA BERITA.`);

// ── 4. Mapping output ke format database ──
return belumAbsen.map(p => ({
  json: {
    ID         : String(p.id),
    Nama       : p.Nama    || p.nama    || p.username || '—',
    NIP        : p.NIP     || p.nip     || '—',
    nomorhp    : p.nomorhp,
    Tanggal    : tanggal,
    Jam        : jam,
    JenisAbsen : 'TANPA BERITA',
    Lokasi     : '-',
    Ket        : 'Otomatis — tidak hadir tanpa keterangan',
    koordinat  : '-'
  }
}));

const inputDate = $input.first().json.timestamp;
const dateObj = new Date(inputDate);
const options = {
  timeZone: 'Asia/Makassar',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};
const localString = dateObj.toLocaleString('en-GB', options);
const [datePart, timePart] = localString.split(', ');
const [day, month, year] = datePart.split('/');
const tanggal = `${year}-${month}-${day}`;
const jam = timePart;
return [{ json: { tanggal, jam } }];

// Tarik data pegawai yang statusnya keterangan
const pegawai = $('Get Pegawai Berketerangan').all().map(i => i.json);
// Tarik ket_temp yang aktif hari ini
const ketAktif = $('Get ket_temp Aktif Hari Ini').all().map(i => i.json);

// Buat set ID dan NIP pegawai yang masih aktif keterangannya
const activeIdSet = new Set();
const activeNipSet = new Set();
ketAktif.forEach(k => {
  if (k.ID_Pegawai) activeIdSet.add(String(k.ID_Pegawai).trim());
  if (k.NIP && String(k.NIP).trim() !== '') activeNipSet.add(String(k.NIP).trim());
});

// Filter: pegawai yang statusnya keterangan TAPI tidak ada ket_temp aktif hari ini
const expired = pegawai.filter(p => {
  const id = String(p.id || '').trim();
  const nip = String(p.NIP || '').trim();
  return !activeIdSet.has(id) && !(nip && activeNipSet.has(nip));
});

if (!expired.length) {
  console.log('[Sync] Semua status keterangan masih aktif hari ini.');
  return [];
}

console.log(`[Sync] ${expired.length} pegawai statusnya di-reset ke AKTIF.`);
return expired.map(p => ({
  json: { id: String(p.id), nama: p.username || p.Nama || '' }
}));
